firmware_template.source:
#include "anomaly_detector.h"
#define MAX_MON 32
typedef struct {
  const char* name;
  float min_val, max_val, rate_limit;
  float last_val;
  unsigned long last_time;
  bool alert;
} monitor_t;
static monitor_t _m[MAX_MON];
static uint8_t _cnt = 0;
static anomaly_cb _cb = nullptr;
void anomaly_setup() { _cnt = 0; Serial.println("[anomaly] OK"); }
uint8_t anomaly_add_monitor(const char*n, float mn, float mx, float rl) {
  if (_cnt >= MAX_MON) return 255;
  _m[_cnt] = {n, mn, mx, rl, 0, 0, false};
  return _cnt++;
}
bool anomaly_check(uint8_t i, float v) {
  if (i >= _cnt) return false;
  monitor_t* m = &_m[i];
  bool alert = false;
  const char* reason = "";
  if (v < m->min_val) { alert = true; reason = "below_min"; }
  else if (v > m->max_val) { alert = true; reason = "above_max"; }
  if (m->last_time > 0) {
    float dt = (millis() - m->last_time) / 1000.0f;
    if (dt > 0 && abs(v - m->last_val) / dt > m->rate_limit) {
      alert = true; reason = "rate_exceeded";
    }
  }
  if (v != v) { alert = true; reason = "nan_detected"; }
  m->last_val = v; m->last_time = millis(); m->alert = alert;
  if (alert && _cb) _cb(m->name, v, reason);
  return alert;
}
bool anomaly_any_alert() {
  for (int i = 0; i < _cnt; i++) if (_m[i].alert) return true;
  return false;
}
void anomaly_on_detect(anomaly_cb cb) { _cb = cb; }
void anomaly_reset() { for (int i = 0; i < _cnt; i++) _m[i].alert = false; }
